<template>
  <a-form :form="form" class="login-form user-layout-login"
          @submit="handleSubmit">
    <a-row :gutter="16">
      <a-col :xs="24" :md="12">
        <a-form-item class="mb-2">
          <a-input-password
              placeholder="Enter your old password..."
              v-decorator="[
                'password',
                {rules: [{ required: true, message: 'Please enter your password!' },{max: 20,message: 'Maximum length was 20 character'},
                {min: 6,message: 'Minimum length was 6 character'},]},
              ]">
            <a-icon slot="prefix" type="lock" :style="{ color: '#a3acb7' }"/>
          </a-input-password>
        </a-form-item>
        <a-form-item class="mb-2">
          <a-input-password
              placeholder="Enter your new password..."
              v-decorator="[
                'password',
                {rules: [{ required: true, message: 'Please enter your password!' },{max: 20,message: 'Maximum length was 20 character'},
                {min: 6,message: 'Minimum length was 6 character'},{validator: validateToNextPassword}]},
              ]">
            <a-icon slot="prefix" type="lock" :style="{ color: '#a3acb7' }"/>
          </a-input-password>
        </a-form-item>
        <a-form-item class="mb-2">
          <a-input-password
              placeholder="Confirm your password..."
              @blur="handleConfirmBlur"
              v-decorator="[
                'confirm',
                {rules: [{ required: true, message: 'Please confirm your password!' },{validator: compareToFirstPassword}]},
              ]">
            <a-icon slot="prefix" type="lock" :style="{ color: '#a3acb7' }"/>
          </a-input-password>
        </a-form-item>
        <div class="form-group mt-4">
          <a-button html-type="submit" type="primary" class="float-right" :loading="loginBtn"
                    :disabled="loginBtn">Save Changes
          </a-button>
        </div>
      </a-col>
    </a-row>
  </a-form>
</template>

<script>
export default {
  name: "ChangePassword",
  data() {
    return {
      form: this.$form.createForm(this, {name: 'coordinated'}),
      loginBtn: false,
    };
  },
  methods: {
    compareToFirstPassword(rule, value, callback) {
      const form = this.form;
      if (value && value !== form.getFieldValue('password')) {
        callback('Two passwords that you enter is inconsistent!');
      } else {
        callback();
      }
    },
    validateToNextPassword(rule, value, callback) {
      const form = this.form;
      if (value && this.confirmDirty) {
        form.validateFields(['confirm'], {force: true});
      }
      callback();
    },
    handleConfirmBlur(e) {
      const value = e.target.value;
      this.confirmDirty = this.confirmDirty || !!value;
    },
    handleSubmit: function (e) {

    }
  }
}
</script>

